import{_ as a,o as r,c as s,ai as o}from"./chunks/framework.DyvBZb4W.js";const p=JSON.parse('{"title":"Mod Works","description":"","frontmatter":{},"headers":[],"relativePath":"en/mods/index.md","filePath":"en/mods/index.md","lastUpdated":1782051941000}'),n={name:"en/mods/index.md"};function t(i,e,d,l,c,h){return r(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="mod-works" tabindex="-1">Mod Works <a class="header-anchor" href="#mod-works" aria-label="Permalink to &quot;Mod Works&quot;">​</a></h1><p>Player-facing pages for Slay the Spire 2 mods developed by Jason Song. Each work page collects feature notes, installation notes, changelogs, FAQ, feedback details, and public credits. Sponsorship is centralized on the <a href="/jasonsong-games/en/support/">site support page</a>.</p><h2 id="slay-the-spire-2" tabindex="-1">Slay the Spire 2 <a class="header-anchor" href="#slay-the-spire-2" aria-label="Permalink to &quot;Slay the Spire 2&quot;">​</a></h2><h3 id="sts2-god-mod" tabindex="-1">STS2 God Mod <a class="header-anchor" href="#sts2-god-mod" aria-label="Permalink to &quot;STS2 God Mod&quot;">​</a></h3><p>Current version: <code>1.7.6</code><br> Type: sandbox tool / testing tool / cheat-style mod<br> Gameplay impact: yes. It directly changes game state.</p><p>God Mod is built for testing, sandbox play, build experiments, and faster run setup. It can edit resources, cards, relics, potions, and combat state, and also supports deck presets, event jumps, campfire helpers, and multiplayer test workflows.</p><ul><li><a href="/jasonsong-games/en/mods/sts2-god-mod/">Overview</a></li><li><a href="/jasonsong-games/en/mods/sts2-god-mod/faq">FAQ</a></li><li><a href="https://pan.quark.cn/s/2c8c2850621d" target="_blank" rel="noreferrer">Quark download</a></li><li><a href="https://www.nexusmods.com/slaythespire2/mods/304" target="_blank" rel="noreferrer">Nexus Mods</a></li><li><a href="https://www.bilibili.com/video/BV1fJXLBuERb" target="_blank" rel="noreferrer">Video demo</a></li><li><a href="/jasonsong-games/en/mods/sts2-god-mod/credits">Credits</a></li><li><a href="/jasonsong-games/en/mods/sts2-god-mod/changelog">Changelog</a></li><li><a href="/jasonsong-games/en/mods/sts2-god-mod/support">Feedback</a></li></ul><h3 id="sts2-map-enhance-mod" tabindex="-1">STS2 Map Enhance Mod <a class="header-anchor" href="#sts2-map-enhance-mod" aria-label="Permalink to &quot;STS2 Map Enhance Mod&quot;">​</a></h3><p>Current version: <code>0.8.0</code><br> Type: map readability / route planning / UI aid<br> Gameplay impact: no direct gameplay changes.</p><p>Map Enhance Mod adds room-type tinting, route analysis, double-click room filtering, room predictions, a mini-map, live previews, and an <code>F8</code> quick toggle so routes and important nodes are easier to read at a glance.</p><ul><li><a href="/jasonsong-games/en/mods/sts2-map-enhance/">Overview</a></li><li><a href="/jasonsong-games/en/mods/sts2-map-enhance/faq">FAQ</a></li><li><a href="https://pan.quark.cn/s/f2902ba27eff" target="_blank" rel="noreferrer">Quark download</a></li><li><a href="https://www.nexusmods.com/slaythespire2/mods/475" target="_blank" rel="noreferrer">Nexus Mods</a></li><li><a href="https://www.bilibili.com/video/BV1XfDSBXEKk" target="_blank" rel="noreferrer">Video demo</a></li><li><a href="/jasonsong-games/en/mods/sts2-map-enhance/credits">Credits</a></li><li><a href="/jasonsong-games/en/mods/sts2-map-enhance/changelog">Changelog</a></li><li><a href="/jasonsong-games/en/mods/sts2-map-enhance/support">Feedback</a></li></ul><h3 id="fantu-character-mod" tabindex="-1">FanTu Character Mod <a class="header-anchor" href="#fantu-character-mod" aria-label="Permalink to &quot;FanTu Character Mod&quot;">​</a></h3><p>Release status: preview / early playable<br> Current version: <code>v0.1.0</code><br> Type: custom character / randomized packs / multi-archetype deckbuilding<br> Gameplay impact: yes. It adds a new character, custom cards, packs, relics, potions, and deckbuilding rules.</p><p>FanTu is a Slay the Spire 2 custom character mod inspired by Packmaster from Slay the Spire 1. Each run combines the character&#39;s base pack with several archetype packs, forming a smaller run-specific card pool that changes the deckbuilding puzzle from run to run.</p><ul><li><a href="/jasonsong-games/en/mods/fantu-character/">Preview</a></li></ul><h3 id="xuanji-character-mod" tabindex="-1">Xuanji Character Mod <a class="header-anchor" href="#xuanji-character-mod" aria-label="Permalink to &quot;Xuanji Character Mod&quot;">​</a></h3><p>Release status: Beta<br> Current version: <code>0.13.0-beta</code><br> Type: custom character / synergy-building / Machine Core planning<br> Gameplay impact: yes. It adds a new character built around encoding, condensing, and synergy planning.</p><p>Xuanji is a male custom character mod for Slay the Spire 2. He uses encoded cards, a Machine Chamber, Machine Cores, and 8 main synergies so players can plan core order and shape defense, burst, draw, Energy, exhaust payoffs, debuffs, long-term growth, and multi-synergy chaining into a coherent deck rhythm.</p><ul><li><a href="/jasonsong-games/en/mods/xuanji-character/">Gameplay overview</a></li><li><a href="/jasonsong-games/en/mods/xuanji-character/synergies">Synergy details</a></li><li><a href="/jasonsong-games/en/mods/xuanji-character/faq">FAQ</a></li><li><a href="/jasonsong-games/en/mods/xuanji-character/credits">Credits</a></li><li><a href="/jasonsong-games/en/mods/xuanji-character/changelog">Changelog</a></li><li><a href="/jasonsong-games/en/mods/xuanji-character/support">Feedback</a></li></ul>',19)])])}const g=a(n,[["render",t]]);export{p as __pageData,g as default};
